query GetReport($code: String!) {
  reportData {
    report(code: $code) {
      title
      code
      fights(killType: All) {
        id
        name
        startTime
        endTime
        kill
        friendlyPlayers
      }
      masterData(translate: true) {
        actors {
          id
          name
          type
          subType
        }
        abilities {
          gameID
          name
          icon
        }
      }
    }
  }
}
